#include<bits/stdc++.h>
using namespace std;
char s[2010];
bool flag[2010][2010];
vector<int> v[2010];
int dp[2010][2010],cnt[2010];
int main()
{
    int n;
    long long ans=0;
    scanf("%s",s+1);
    n=strlen(s+1);
    for(int i=1;i<=n;i++)
    {
        int l=i,r=i;
        while(l>=1&&r<=n&&s[l]==s[r])
        {
            cnt[l]++;
            v[l].push_back(r);
            flag[l][r]=true;
            l--;
            r++;
        }
    }
    for(int i=1;i<n;i++)
    {
        int l=i,r=i+1;
        while(l>=1&&r<=n&&s[l]==s[r])
        {
            cnt[l]++;
            v[l].push_back(r);
            flag[l][r]=true;
            l--;
            r++;
        }
    }
    for(int i=n;i>=1;i--)
    {
        cnt[i]+=cnt[i+1];
    }
    for(int i=1;i<=n;i++)
    {
        sort(v[i].begin(),v[i].end());
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=i;j<=n;j++)if(flag[i][j])
        {
            ans+=cnt[j+1];
        }
    }
    printf("%lld",ans);
    return 0;
}
